class GeminiAdapter extends BaseAdapter {
  constructor() {
    super({ id: 'gemini', label: 'Gemini', bin: 'gemini' });
  }

  buildCommand(run, context) {
    return {
      command: 'gemini',
      args: [
        '-p', run.prompt,
        '--output-format', 'stream-json',
        '--yolo',
      ],
      cwd: context.workdir,
      env: process.env,
    };
  }

