        text,
        phase: 'coding',
      }];
    }
    if (payload.type === 'result') {
      if (payload.subtype === 'success' || !payload.is_error) {
        return [{
          type: 'result',
          status: 'success',
          summary: payload.result || 'Gemini 작업이 완료되었습니다.',
